const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authUrl = 'https://authorization-server.com/auth';
const apiUrl = 'https://api-server.com/resource';

function redirectToAuth() {
    const scope = 'YOUR_SCOPES';
    const responseType = 'token';
    const authRequestUrl = `${authUrl}?response_type=${responseType}&client_id=${clientId}&redirect_uri=${redirectUri}&scope=${scope}`;
    window.location.href = authRequestUrl;
}

function parseAccessTokenFromUrl() {
    const hash = window.location.hash;
    const params = new URLSearchParams(hash.substr(1));
    return params.get('access_token');
}

function storeAccessToken(token) {
    sessionStorage.setItem('access_token', token);
}

function getAccessToken() {
    return sessionStorage.getItem('access_token');
}

